var findShortestCycle = function(n, edges) {
    const adj = Array.from({length: n}, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }
    let best = -1;
    for (let root = 0; root < n; root++) {
        const dist = new Array(n).fill(-1);
        const parent = new Array(n).fill(-1);
        dist[root] = 0;
        const q = [root];
        let head = 0;
        while (head < q.length) {
            const u = q[head++];
            for (const v of adj[u]) {
                if (dist[v] === -1) {
                    dist[v] = dist[u] + 1;
                    parent[v] = u;
                    q.push(v);
                } else if (parent[u] !== v) {
                    const cand = dist[u] + dist[v] + 1;
                    if (best === -1 || cand < best) best = cand;
                }
            }
        }
    }
    return best;
};
